import Star from "./Star";

function StarRatingByUser({rating,max = 5}) {
  return (
  <div style={{ display: "flex", gap: "4px" }}>
    {Array.from({ length: 5 }, (_, i) => (
      <Star key={i} filled={i < rating} fillPercent={0.7}/>
    ))}
  </div>
  );
}

export default StarRatingByUser;
